@Scenario
fun myScenario() {
    val myScenario = scenario("hello-world") {
        minionsCount = 1000
        rampUp {
            regular(1000, 50)
        }
    }
    myScenario.start() // Root branch receiving all minions.
        .returns<string>{ "My input" }
    myScenario // Second branch visited by a unique minion.
        .returns<String>{ "My other input" }
}

@Scenario
fun myScenario() {
    val myScenario = scenario("hello-world"){
    .start()
        .split {
             .map {
             .returns<String>{ "My other input"
             }
            flatten() {
                .filterNotNull()
            .returns<String>{ "My other input" }
            }
        }
    }
}

scenario("hello-netty-udp-world") {
    minionsCount = 100
    rampUp {
        regular(100, minionsCount) // Start all at once.
    }
    .start()
    .netty()
    .tcp { // This step is the root of the scenario.
        name = "my-tcp"
        connect {
            address("localhost", 3000)
            noDelay = true
        }
        request { tcpRequest1 }
        metrics { connectTime = true }
    }
    .reuseTcp("my-tcp") {
        name = "reuse-tcp" // This step is a successor of the previos step and receives the previos step's output as its input.
        iterate(20, Duration.ofMillis(100))
        request { tcpRequest2 }
    }
}

reuseTcp("my-tcp") {
    request { tcpRequest2 }
}.configure {
    name = "reuse-tcp"
    iterate(20, Duration.ofMillis(100))
    retryPolicy(instanceOfRetryPolicy)
    timeout(2000)
}

